import java.io.*;import java.util.*;class Main{static int trap(int[][]g){int m=g.length,n=g[0].length;if(m<3||n<3)return 0;boolean[][]seen=new boolean[m][n];PriorityQueue<int[]>pq=new PriorityQueue<>(Comparator.comparingInt(a->a[0]));for(int r=0;r<m;r++){add(g,seen,pq,r,0);add(g,seen,pq,r,n-1);}for(int c=0;c<n;c++){add(g,seen,pq,0,c);add(g,seen,pq,m-1,c);}int water=0;int[]d={1,0,-1,0,1};while(!pq.isEmpty()){int[]cur=pq.poll();for(int k=0;k<4;k++){int nr=cur[1]+d[k],nc=cur[2]+d[k+1];if(nr<0||nr>=m||nc<0||nc>=n||seen[nr][nc])continue;seen[nr][nc]=true;int nh=g[nr][nc];if(nh<cur[0]){water+=cur[0]-nh;nh=cur[0];}pq.add(new int[]{nh,nr,nc});}}return water;}static void add(int[][]g,boolean[][]s,PriorityQueue<int[]>pq,int r,int c){if(!s[r][c]){s[r][c]=true;pq.add(new int[]{g[r][c],r,c});}}public static void main(String[]a)throws Exception{String text=new String(System.in.readAllBytes()).trim();if(text.isEmpty())return;String[]d=text.split("\\s+");int idx=0,t=Integer.parseInt(d[idx++]);StringBuilder out=new StringBuilder();for(int tc=0;tc<t;tc++){int m=Integer.parseInt(d[idx++]),n=Integer.parseInt(d[idx++]);int[][]g=new int[m][n];for(int i=0;i<m;i++)for(int j=0;j<n;j++)g[i][j]=Integer.parseInt(d[idx++]);if(tc>0)out.append("\n\n");out.append(trap(g));}System.out.print(out);}}
